svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
    var dataLayerEl = document.getElementById('data-layer');
    var itemLayer = document.getElementById('item-layer');
    var outerBoundary = document.getElementById('outer-boundary');
    var legendRoot = document.getElementById('legend-root');
    var tip = document.getElementById('tip');
    var plotL = 68;
    var plotR = 850;
    var plotT = 100;
    var plotB = 500;
    var plotShiftX = 0;

    var itemsData = [
      { id: 'item-std', ci: 2, depth: 1, value: '5,968', label: 'Standard Class', pct: '54%', cx: 382, cy: 280, r: 120, lines: ['Standard', 'Class'], fontSize: 13 },
      { id: 'item-fst', ci: 6, depth: 1, value: '1,992', label: 'First Class', pct: '18%', cx: 574, cy: 249, r: 75, lines: ['First Class'], fontSize: 12 },
      { id: 'item-sec', ci: 5, depth: 1, value: '1,945', label: 'Second Class', pct: '18%', cx: 520, cy: 412, r: 72, lines: ['Second Class'], fontSize: 12 },
      { id: 'item-sd', ci: 3, depth: 2, value: '543', label: 'Same Day', pct: '5%', cx: 612, cy: 355, r: 37, lines: ['Same Day'], fontSize: 10 }
    ];

    var itemNodes = [];
    var revealNodes = [];
    var revealDelays = [];

    function buildItemNode(entry) {
      var group = ctx.el('g', {
        id: entry.id,
        'class': 'item',
        'data-ci': String(entry.ci),
        'data-depth': String(entry.depth),
        'data-val': entry.value,
        'data-lbl': entry.label,
        'data-pct': entry.pct,
        'data-item-cx': String(entry.cx),
        'data-item-top': String(entry.cy)
      });
      var circle = ctx.el('circle', {
        cx: entry.cx,
        cy: entry.cy,
        r: entry.r
      });
      group.appendChild(circle);

      entry.lines.forEach(function (line, index) {
        var text = ctx.el('text', {
          x: entry.cx,
          y: entry.cy + (entry.lines.length === 1 ? 3 : (index === 0 ? -5 : 12)),
          'text-anchor': 'middle',
          'font-size': String(entry.fontSize),
          'font-weight': '500',
          'class': 'item-label'
        });
        text.textContent = line;
        group.appendChild(text);
      });

      itemLayer.appendChild(group);
      return group;
    }

    function recolor() {
      itemNodes.forEach(function (node) {
        var circle = node.querySelector('circle');
        var ci = Number(node.getAttribute('data-ci')) || 1;
        var depth = Number(node.getAttribute('data-depth')) || 0;
        circle.setAttribute('fill', ctx.getSeriesDepthColor(ci, depth));
      });
    }

    itemsData.forEach(function (entry, index) {
      var node = buildItemNode(entry);
      itemNodes.push(node);
      revealNodes.push(node);
      revealDelays.push(0.08 + ctx.getStaggerDelay(index, itemsData.length, 1.0, svgEl));
    });

    revealNodes.unshift(outerBoundary);
    revealDelays.unshift(0);

    ctx.initRevealSequence(revealNodes, {
      animationName: 'fadeIn',
      duration: 0.8,
      easing: 'ease-out',
      delays: revealDelays
    });

    ctx.initStandardLegend({
      legendEl: legendRoot,
      title: 'SERIES',
      items: [
        { cls: 'series-2', label: 'Standard Class', value: '5,968' },
        { cls: 'series-6', label: 'First Class', value: '1,992' },
        { cls: 'series-5', label: 'Second Class', value: '1,945' },
        { cls: 'series-3', label: 'Same Day', value: '543' }
      ]
    });
    plotShiftX = ctx.rebalancePlotArea({
      legendEl: legendRoot,
      measureNodes: [dataLayerEl],
      moveNodes: [dataLayerEl],
      outerLeft: 24,
      legendGap: 32
    }).shiftX || 0;

    ctx.initStandardTooltip(dataLayerEl, itemNodes, {
      tip: tip,
      plotL: plotL,
      plotR: plotR,
      plotT: plotT,
      plotB: plotB,
      placement: 'side',
      minWidth: 220,
      paddingX: 20,
      paddingY: 18,
      lineHeights: [42, 32, 32],
      trackPointer: false,
      getAnchor: function (itemEl) {
        return {
          x: (Number(itemEl.getAttribute('data-item-cx')) || 0) + plotShiftX,
          y: Number(itemEl.getAttribute('data-item-top')) || 0
        };
      },
      getContent: function (itemEl) {
        return {
          primary: itemEl.getAttribute('data-val') || '',
          label: itemEl.getAttribute('data-lbl') || '',
          meta: itemEl.getAttribute('data-pct') || ''
        };
      },
      onActivate: function (itemEl) {
        dataLayerEl.classList.add('hovering');
        itemNodes.forEach(function (node) {
          node.classList.toggle('active', node === itemEl);
        });
      },
      onDeactivate: function () {
        dataLayerEl.classList.remove('hovering');
        itemNodes.forEach(function (node) {
          node.classList.remove('active');
        });
      },
      leaveTarget: dataLayerEl
    });

    ctx.markReadyAfterReveal(dataLayerEl, {
      delays: revealDelays,
      duration: 0.8,
      buffer: 0.1
    });

    svgEl._onModeChange = function () { recolor(); };
    recolor();
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
